// AllIcons returns all 32 icons in a flat map.
func AllIcons() map[string]string {
	all := make(map[string]string)
	for k, v := range Source {
		all["source-"+k] = v
	}
	for k, v := range Artifact {
		all["artifact-"+k] = v
	}
	for k, v := range Status {
		all["status-"+k] = v
	}
	for k, v := range Action {
		all["action-"+k] = v
	}
	for k, v := range Navigation {
		all["nav-"+k] = v
	}
	return all
}
